#!/usr/bin/env python3
"""Generated by superpower-adapter."""

from __future__ import annotations

import argparse
import hashlib
import json
import re
import sys
from pathlib import Path
from typing import Any

KIND = "superpower-adapter.source-truth-constraints"
SCHEMA_VERSION_V1 = 1
SCHEMA_VERSION_V2 = 2
CONSTRAINT_CATEGORIES = ("implementation", "test", "review", "general")
ROLE_CATEGORIES = {
    "implementer": ("implementation", "test", "general"),
    "reviewer": ("implementation", "test", "review", "general"),
}
PLAN_WIDE_TASKS = {"all", "plan-wide", "plan_wide", "*"}
DESTINATION_KINDS = {"task-bound", "global"}
TASK_FINGERPRINT_NORMALIZATION = "superpower-adapter-task-text-v1"
TASK_HEADING_RE = re.compile(r"^### Task\s+([A-Za-z0-9][A-Za-z0-9_-]*):\s*(.+?)\s*$")
TASK_OR_HIGHER_HEADING_RE = re.compile(r"^#{1,3}\s+")
HEX_SHA256_RE = re.compile(r"^[0-9a-f]{64}$")


class ValidationError(Exception):
    pass


class FingerprintError(Exception):
    pass


def _as_list(value: Any, field: str) -> list[Any]:
    if value is None:
        return []
    if not isinstance(value, list):
        raise ValidationError(f"{field} must be a list")
    return value


def _as_dict(value: Any, field: str) -> dict[str, Any]:
    if not isinstance(value, dict):
        raise ValidationError(f"{field} must be an object")
    return value


def _load_constraints(path: Path) -> dict[str, Any]:
    try:
        raw = path.read_text(encoding="utf-8")
    except OSError as exc:
        raise ValidationError(f"Cannot read source-truth constraints: {exc}") from exc
    try:
        data = json.loads(raw)
    except json.JSONDecodeError as exc:
        raise ValidationError(f"Invalid JSON: {exc}") from exc
    return _as_dict(data, "source-truth constraints")


def _validate_constraint_categories(constraints: dict[str, Any], field: str, strict: bool) -> list[str]:
    caveats: list[str] = []
    unknown = sorted(set(constraints) - set(CONSTRAINT_CATEGORIES))
    if unknown:
        message = f"{field} contains unsupported categories: {', '.join(unknown)}"
        if strict:
            raise ValidationError(message)
        caveats.append(message)
    for category in CONSTRAINT_CATEGORIES:
        _as_list(constraints.get(category), f"{field}.{category}")
    return caveats


def _validate_v1_constraints(data: dict[str, Any], strict: bool) -> list[str]:
    caveats: list[str] = []
    if data.get("kind") != KIND:
        raise ValidationError(f"kind must be {KIND}")
    if data.get("status") not in {"passed", "needs_revision", "blocked", "not_configured"}:
        raise ValidationError("status must be one of: passed, needs_revision, blocked, not_configured")

    for index, item in enumerate(_as_list(data.get("taskConstraints"), "taskConstraints")):
        constraint = _as_dict(item, f"taskConstraints[{index}]")
        if not constraint.get("taskId"):
            raise ValidationError(f"taskConstraints[{index}].taskId is required")
        _as_list(constraint.get("appliesTo"), f"taskConstraints[{index}].appliesTo")
        constraints = _as_dict(constraint.get("constraints"), f"taskConstraints[{index}].constraints")
        caveats.extend(_validate_constraint_categories(constraints, f"taskConstraints[{index}].constraints", strict))
        if "sourceRefs" in constraint:
            _as_list(constraint.get("sourceRefs"), f"taskConstraints[{index}].sourceRefs")
    return caveats


def _constraint_id(constraint: dict[str, Any], field: str) -> str:
    constraint_id = constraint.get("constraintId")
    if not isinstance(constraint_id, str) or not constraint_id.strip():
        raise ValidationError(f"{field}.constraintId is required")
    return constraint_id


def _constraint_sets_by_id(data: dict[str, Any]) -> dict[str, dict[str, Any]]:
    constraints_by_id: dict[str, dict[str, Any]] = {}
    for index, item in enumerate(_as_list(data.get("constraintSets"), "constraintSets")):
        constraint = _as_dict(item, f"constraintSets[{index}]")
        constraint_id = _constraint_id(constraint, f"constraintSets[{index}]")
        if constraint_id in constraints_by_id:
            raise ValidationError(f"constraintSets[{index}].constraintId duplicates {constraint_id}")
        constraints_by_id[constraint_id] = constraint
    return constraints_by_id


def _validate_task_fingerprint(task_ref: dict[str, Any], field: str) -> None:
    fingerprint = _as_dict(task_ref.get("taskFingerprint"), f"{field}.taskFingerprint")
    if fingerprint.get("algorithm") != "sha256":
        raise ValidationError(f"{field}.taskFingerprint.algorithm must be sha256")
    if fingerprint.get("normalization") != TASK_FINGERPRINT_NORMALIZATION:
        raise ValidationError(f"{field}.taskFingerprint.normalization must be {TASK_FINGERPRINT_NORMALIZATION}")
    hash_value = fingerprint.get("hash")
    if not isinstance(hash_value, str) or not HEX_SHA256_RE.match(hash_value):
        raise ValidationError(f"{field}.taskFingerprint.hash must be a 64-character lowercase sha256 hex digest")


def _resolve_constraint_ref(constraints_by_id: dict[str, dict[str, Any]], ref_obj: dict[str, Any], field: str) -> str:
    constraint_ref = ref_obj.get("constraintRef")
    if not isinstance(constraint_ref, str) or not constraint_ref.strip():
        raise ValidationError(f"{field}.constraintRef is required")
    if constraint_ref not in constraints_by_id:
        raise ValidationError(f"{field}.constraintRef does not resolve: {constraint_ref}")
    return constraint_ref


def _validate_constraint_ref_list(constraints_by_id: dict[str, dict[str, Any]], refs: list[Any], field: str) -> list[str]:
    constraint_ids: list[str] = []
    seen: set[str] = set()
    for index, ref in enumerate(refs):
        ref_obj = _as_dict(ref, f"{field}[{index}]")
        if not str(ref_obj.get("reason") or "").strip():
            raise ValidationError(f"{field}[{index}].reason is required")
        constraint_id = _resolve_constraint_ref(constraints_by_id, ref_obj, f"{field}[{index}]")
        if constraint_id in seen:
            raise ValidationError(f"{field}[{index}] duplicates constraintRef {constraint_id}")
        seen.add(constraint_id)
        constraint_ids.append(constraint_id)
    return constraint_ids


def _destination_kind(constraint: dict[str, Any], constraint_id: str) -> str:
    destination = _as_dict(constraint.get("destination"), f"constraintSets[{constraint_id}].destination")
    kind = destination.get("kind")
    if kind not in DESTINATION_KINDS:
        raise ValidationError(f"constraintSets[{constraint_id}].destination.kind must be one of {', '.join(sorted(DESTINATION_KINDS))}")
    if not str(destination.get("reason") or "").strip():
        raise ValidationError(f"constraintSets[{constraint_id}].destination.reason is required")
    return str(kind)


def _validate_v2_execution_ready(data: dict[str, Any], constraints_by_id: dict[str, dict[str, Any]]) -> None:
    task_routing = _as_dict(data.get("taskRouting"), "taskRouting")
    if task_routing.get("status") != "confirmed":
        raise ValidationError("taskRouting.status must be confirmed for execution-ready source-truth constraints")
    if task_routing.get("selectedConstraintsFrozen") is not True:
        raise ValidationError("taskRouting.selectedConstraintsFrozen must be true for execution-ready source-truth constraints")

    destinations = {constraint_id: _destination_kind(constraint, constraint_id) for constraint_id, constraint in constraints_by_id.items()}

    global_refs = _as_list(data.get("globalConstraintRefs"), "globalConstraintRefs")
    global_ids = set(_validate_constraint_ref_list(constraints_by_id, global_refs, "globalConstraintRefs"))
    for constraint_id in global_ids:
        if destinations[constraint_id] != "global":
            raise ValidationError(f"globalConstraintRefs references non-global constraint {constraint_id}")

    task_refs = _as_list(data.get("taskConstraintRefs"), "taskConstraintRefs")
    task_ids: set[str] = set()
    task_bound_ids: set[str] = set()
    for index, task_ref in enumerate(task_refs):
        task_obj = _as_dict(task_ref, f"taskConstraintRefs[{index}]")
        task_id = task_obj.get("taskId")
        if not isinstance(task_id, str) or not task_id.strip():
            raise ValidationError(f"taskConstraintRefs[{index}].taskId is required")
        if task_id in task_ids:
            raise ValidationError(f"taskConstraintRefs[{index}].taskId duplicates {task_id}")
        task_ids.add(task_id)
        if not isinstance(task_obj.get("taskTitle"), str) or not task_obj.get("taskTitle", "").strip():
            raise ValidationError(f"taskConstraintRefs[{index}].taskTitle is required")
        _validate_task_fingerprint(task_obj, f"taskConstraintRefs[{index}]")
        constraint_ids = _validate_constraint_ref_list(
            constraints_by_id,
            _as_list(task_obj.get("constraintRefs"), f"taskConstraintRefs[{index}].constraintRefs"),
            f"taskConstraintRefs[{index}].constraintRefs",
        )
        for constraint_id in constraint_ids:
            if destinations[constraint_id] == "global":
                raise ValidationError(f"taskConstraintRefs[{index}] references global constraint {constraint_id}; use globalConstraintRefs")
            task_bound_ids.add(constraint_id)

    for constraint_id, kind in destinations.items():
        if kind == "global" and constraint_id not in global_ids:
            raise ValidationError(f"global constraint {constraint_id} is not referenced by globalConstraintRefs")
        if kind == "task-bound" and constraint_id not in task_bound_ids:
            raise ValidationError(f"task-bound constraint {constraint_id} is not referenced by taskConstraintRefs")


def _validate_v2_constraints(data: dict[str, Any], strict: bool, execution_ready: bool) -> list[str]:
    caveats: list[str] = []
    if data.get("kind") != KIND:
        raise ValidationError(f"kind must be {KIND}")
    if data.get("status") not in {"passed", "needs_revision", "blocked", "not_configured"}:
        raise ValidationError("status must be one of: passed, needs_revision, blocked, not_configured")
    if strict and "taskConstraints" in data:
        raise ValidationError("schemaVersion 2 must use constraintSets/taskConstraintRefs, not legacy taskConstraints")

    constraints_by_id = _constraint_sets_by_id(data)
    for constraint_id, constraint in constraints_by_id.items():
        if strict and "appliesTo" in constraint:
            raise ValidationError(f"constraintSets[{constraint_id}].appliesTo is not allowed in schemaVersion 2")
        if strict and "taskId" in constraint:
            raise ValidationError(f"constraintSets[{constraint_id}].taskId is not allowed in schemaVersion 2")
        _destination_kind(constraint, constraint_id)
        constraints = _as_dict(constraint.get("constraints"), f"constraintSets[{constraint_id}].constraints")
        caveats.extend(_validate_constraint_categories(constraints, f"constraintSets[{constraint_id}].constraints", strict))
        if "sourceRefs" in constraint:
            _as_list(constraint.get("sourceRefs"), f"constraintSets[{constraint_id}].sourceRefs")
        if "findingRefs" in constraint:
            _as_list(constraint.get("findingRefs"), f"constraintSets[{constraint_id}].findingRefs")
        if "caveats" in constraint:
            _as_list(constraint.get("caveats"), f"constraintSets[{constraint_id}].caveats")
    if execution_ready:
        _validate_v2_execution_ready(data, constraints_by_id)
    return caveats


def _validate_constraints(data: dict[str, Any], strict: bool, execution_ready: bool = False) -> list[str]:
    schema_version = data.get("schemaVersion")
    if schema_version == SCHEMA_VERSION_V1:
        return _validate_v1_constraints(data, strict)
    if schema_version == SCHEMA_VERSION_V2:
        return _validate_v2_constraints(data, strict, execution_ready)
    raise ValidationError(f"schemaVersion must be {SCHEMA_VERSION_V1} or {SCHEMA_VERSION_V2}")


def _task_matches_v1(constraint: dict[str, Any], requested_tasks: set[str]) -> bool:
    applies_to = [str(item).strip() for item in _as_list(constraint.get("appliesTo"), "appliesTo") if str(item).strip()]
    if not applies_to:
        return False
    normalized = {item.lower() for item in applies_to}
    if normalized & PLAN_WIDE_TASKS:
        return True
    return bool(set(applies_to) & requested_tasks)


def _matching_v1_constraints(data: dict[str, Any], tasks: list[str]) -> list[dict[str, Any]]:
    requested = {task.strip() for task in tasks if task.strip()}
    matched: list[dict[str, Any]] = []
    for item in _as_list(data.get("taskConstraints"), "taskConstraints"):
        constraint = _as_dict(item, "taskConstraints[]")
        if _task_matches_v1(constraint, requested):
            matched.append(constraint)
    return matched


def _task_constraint_ids(data: dict[str, Any], task_id: str) -> list[str]:
    constraints_by_id = _constraint_sets_by_id(data)
    constraint_ids: list[str] = []
    for index, ref in enumerate(_as_list(data.get("globalConstraintRefs"), "globalConstraintRefs")):
        constraint_ids.append(_resolve_constraint_ref(constraints_by_id, _as_dict(ref, f"globalConstraintRefs[{index}]"), f"globalConstraintRefs[{index}]"))

    matches = [
        _as_dict(task_ref, "taskConstraintRefs[]")
        for task_ref in _as_list(data.get("taskConstraintRefs"), "taskConstraintRefs")
        if _as_dict(task_ref, "taskConstraintRefs[]").get("taskId") == task_id
    ]
    if len(matches) != 1:
        raise ValidationError(f"taskConstraintRefs must contain exactly one entry for taskId {task_id}")
    for index, ref in enumerate(_as_list(matches[0].get("constraintRefs"), f"taskConstraintRefs[{task_id}].constraintRefs")):
        constraint_id = _resolve_constraint_ref(
            constraints_by_id,
            _as_dict(ref, f"taskConstraintRefs[{task_id}].constraintRefs[{index}]"),
            f"taskConstraintRefs[{task_id}].constraintRefs[{index}]",
        )
        if constraint_id not in constraint_ids:
            constraint_ids.append(constraint_id)
    return constraint_ids


def _append_constraints(lines: list[str], constraints: dict[str, Any], role: str) -> None:
    for category in ROLE_CATEGORIES[role]:
        items = _as_list(constraints.get(category), f"constraints.{category}")
        if not items:
            continue
        lines.append(f"#### {category.capitalize()} constraints")
        for item in items:
            lines.append(f"- {item}")


def _format_bool(value: Any) -> str:
    return "true" if bool(value) else "false"


def render_v1_markdown(data: dict[str, Any], tasks: list[str], role: str) -> str:
    if data.get("status") == "not_configured":
        return "No configured source-of-truth constraints for this plan."
    if data.get("status") == "blocked":
        return "## Source-of-Truth Constraints\n\n- Plan source-of-truth verification is blocked; stop and return to planning before implementation."
    constraints = _matching_v1_constraints(data, tasks)
    if not constraints:
        return "No applicable source-of-truth constraints for this task/role."

    lines = ["## Source-of-Truth Constraints", ""]
    for constraint in constraints:
        task_id = constraint.get("taskId", "unknown task")
        lines.append(f"### Constraint Set: `{task_id}`")
        applies = ", ".join(str(item) for item in _as_list(constraint.get("appliesTo"), "appliesTo"))
        if applies:
            lines.append(f"- Applies to: {applies}")
        lines.append(f"- Hard constraint: `{'true' if constraint.get('hardConstraint') else 'false'}`")
        for caveat in _as_list(constraint.get("caveats"), "constraint.caveats"):
            lines.append(f"- Caveat: {caveat}")
        _append_constraints(lines, _as_dict(constraint.get("constraints"), "constraints"), role)
        lines.append("")
    for caveat in _as_list(data.get("caveats"), "caveats"):
        lines.append(f"- Source-of-truth caveat: {caveat}")
    return "\n".join(lines).rstrip()


def render_v2_markdown(data: dict[str, Any], task_id: str, role: str) -> str:
    if data.get("status") == "not_configured":
        return "No configured source-of-truth constraints for this plan."
    if data.get("status") == "blocked":
        return "## Source-of-Truth Constraints\n\n- Plan source-of-truth verification is blocked; stop and return to planning before implementation."

    constraints_by_id = _constraint_sets_by_id(data)
    selected_ids = _task_constraint_ids(data, task_id)
    if not selected_ids:
        return f"No applicable source-of-truth constraints for task `{task_id}` and role `{role}`."

    lines = ["## Source-of-Truth Constraints", "", f"- Task ID: `{task_id}`", ""]
    for constraint_id in selected_ids:
        constraint = constraints_by_id[constraint_id]
        lines.append(f"### Constraint Set: `{constraint_id}`")
        if constraint.get("title"):
            lines.append(f"- Title: {constraint['title']}")
        lines.append(f"- Hard constraint: `{_format_bool(constraint.get('hardConstraint'))}`")
        destination = constraint.get("destination")
        if isinstance(destination, dict):
            lines.append(f"- Destination: `{destination.get('kind')}`")
            if destination.get("reason"):
                lines.append(f"- Destination reason: {destination['reason']}")
        for caveat in _as_list(constraint.get("caveats"), "constraint.caveats"):
            lines.append(f"- Caveat: {caveat}")
        _append_constraints(lines, _as_dict(constraint.get("constraints"), "constraints"), role)
        lines.append("")
    for caveat in _as_list(data.get("caveats"), "caveats"):
        lines.append(f"- Source-of-truth caveat: {caveat}")
    return "\n".join(lines).rstrip()


def _normalize_task_text(task_text: str) -> str:
    lines = task_text.replace("\r\n", "\n").replace("\r", "\n").split("\n")
    lines = [line.rstrip() for line in lines]
    while lines and not lines[0]:
        lines.pop(0)
    while lines and not lines[-1]:
        lines.pop()
    return "\n".join(lines) + "\n"


def _task_fingerprint(task_text: str) -> str:
    normalized = _normalize_task_text(task_text)
    return hashlib.sha256(normalized.encode("utf-8")).hexdigest()


def extract_plan_tasks(plan_path: Path) -> dict[str, dict[str, str]]:
    try:
        text = plan_path.read_text(encoding="utf-8")
    except OSError as exc:
        raise FingerprintError(f"Cannot read plan: {exc}") from exc
    lines = text.replace("\r\n", "\n").replace("\r", "\n").split("\n")
    starts: list[tuple[int, str, str]] = []
    for index, line in enumerate(lines):
        match = TASK_HEADING_RE.match(line)
        if match:
            starts.append((index, match.group(1), match.group(2)))
    if not starts:
        raise FingerprintError("No stable task headings found; expected headings like `### Task T1: Title`")

    tasks: dict[str, dict[str, str]] = {}
    for position, (start, task_id, title) in enumerate(starts):
        if task_id in tasks:
            raise FingerprintError(f"Duplicate task id in plan: {task_id}")
        end = len(lines)
        next_task_start = starts[position + 1][0] if position + 1 < len(starts) else None
        for index in range(start + 1, len(lines)):
            if next_task_start is not None and index == next_task_start:
                end = index
                break
            if TASK_OR_HIGHER_HEADING_RE.match(lines[index]) and not lines[index].startswith("####"):
                end = index
                break
        task_text = "\n".join(lines[start:end])
        tasks[task_id] = {"title": title, "text": task_text, "hash": _task_fingerprint(task_text)}
    return tasks


def fingerprint_preflight(data: dict[str, Any], plan_path: Path) -> str:
    if data.get("schemaVersion") != SCHEMA_VERSION_V2:
        raise FingerprintError("fingerprint preflight requires schemaVersion 2 source-truth constraints")
    plan_tasks = extract_plan_tasks(plan_path)
    sidecar_tasks: dict[str, dict[str, Any]] = {}
    errors: list[str] = []
    for index, task_ref in enumerate(_as_list(data.get("taskConstraintRefs"), "taskConstraintRefs")):
        task_obj = _as_dict(task_ref, f"taskConstraintRefs[{index}]")
        task_id = task_obj.get("taskId")
        if not isinstance(task_id, str) or not task_id:
            errors.append(f"taskConstraintRefs[{index}] missing taskId")
            continue
        if task_id in sidecar_tasks:
            errors.append(f"duplicate sidecar taskId: {task_id}")
            continue
        sidecar_tasks[task_id] = task_obj

    for task_id, task in plan_tasks.items():
        sidecar = sidecar_tasks.get(task_id)
        if not sidecar:
            errors.append(f"plan task missing from taskConstraintRefs: {task_id}")
            continue
        fingerprint = _as_dict(sidecar.get("taskFingerprint"), f"taskConstraintRefs[{task_id}].taskFingerprint")
        if fingerprint.get("hash") != task["hash"]:
            errors.append(f"fingerprint mismatch for {task_id}: expected {fingerprint.get('hash')}, current {task['hash']}")

    for task_id in sorted(set(sidecar_tasks) - set(plan_tasks)):
        errors.append(f"taskConstraintRefs contains task not found in plan: {task_id}")

    if errors:
        raise FingerprintError("\n".join(errors))
    return f"fingerprint preflight passed for {len(plan_tasks)} task(s)"


def main() -> int:
    parser = argparse.ArgumentParser(description="Validate, filter, and render source-truth constraints JSON.")
    parser.add_argument("constraints_path", help="Path to docs/superpowers/plans/<plan-stem>.source-truth-constraints.json")
    parser.add_argument("--task", action="append", default=[], help="Deprecated schemaVersion 1 task id or label to include; repeatable")
    parser.add_argument("--task-id", help="Render schemaVersion 2 constraints bound to the finalized plan task id, plus global refs")
    parser.add_argument("--plan-path", help="Implementation plan path used for task fingerprint preflight")
    parser.add_argument("--execution-ready", action="store_true", help="Require confirmed taskConstraintRefs/globalConstraintRefs routing suitable for execution")
    parser.add_argument("--fingerprint-preflight", action="store_true", help="Compare taskConstraintRefs fingerprints against the current plan task text")
    parser.add_argument("--role", choices=["implementer", "reviewer"], default="implementer")
    parser.add_argument("--format", choices=["markdown"], default="markdown")
    parser.add_argument("--validate-only", action="store_true")
    parser.add_argument("--strict", action="store_true")
    args = parser.parse_args()

    try:
        data = _load_constraints(Path(args.constraints_path))
        caveats = _validate_constraints(data, args.strict, args.execution_ready)
        schema_version = data.get("schemaVersion")
        if args.fingerprint_preflight:
            if not args.plan_path:
                raise ValidationError("--fingerprint-preflight requires --plan-path")
            print(fingerprint_preflight(data, Path(args.plan_path)))
            return 0
        if args.validate_only:
            for caveat in caveats:
                print(f"Warning: {caveat}", file=sys.stderr)
            print("source-truth constraints JSON is valid")
            return 0
        if schema_version == SCHEMA_VERSION_V2:
            if args.task and not args.task_id:
                raise ValidationError("schemaVersion 2 source-truth constraints require --task-id; legacy --task routing is not supported")
            if not args.task_id:
                raise ValidationError("schemaVersion 2 source-truth constraints require --task-id unless --validate-only is used")
            print(render_v2_markdown(data, args.task_id, args.role))
            return 0
        if not args.task:
            raise ValidationError("At least one --task is required for schemaVersion 1 unless --validate-only is used")
        print(render_v1_markdown(data, args.task, args.role))
        return 0
    except (ValidationError, FingerprintError) as exc:
        print(f"Error: {exc}", file=sys.stderr)
        return 1


if __name__ == "__main__":
    raise SystemExit(main())
